import{_ as i,C as t,o as l,c as r,ai as e,E as n,w as s,a as c}from"./chunks/framework.BH_J6TYN.js";const P=JSON.parse('{"title":"Panel flotante","description":"Cómo activar y usar el panel de administración flotante desde escritorio y móvil","frontmatter":{"title":"Panel flotante","description":"Cómo activar y usar el panel de administración flotante desde escritorio y móvil"},"headers":[],"relativePath":"studio/panel-flotante.md","filePath":"studio/panel-flotante.md"}'),d={name:"studio/panel-flotante.md"};function u(p,a,m,h,b,g){const o=t("Tip");return l(),r("div",null,[a[1]||(a[1]=e('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>El panel flotante es la interfaz de administración de SYNTIweb. No es una URL separada — aparece <strong>encima de tu página</strong> como una capa superpuesta. Está diseñado para que puedas editar tu negocio sin salir de tu propia página.</p><h2 id="¿como-lo-activo" tabindex="-1">¿Cómo lo activo? <a class="header-anchor" href="#¿como-lo-activo" aria-label="Permalink to &quot;¿Cómo lo activo?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dispositivo</th><th>Cómo activarlo</th></tr></thead><tbody><tr><td><strong>Escritorio</strong></td><td>Presiona <strong>Alt+S</strong> en el teclado</td></tr><tr><td><strong>Móvil</strong></td><td>Mantén presionado el <strong>logo de tu negocio</strong> durante 3 segundos</td></tr></tbody></table><p>Luego ingresa tu <strong>PIN de 4 dígitos</strong> para acceder.</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><ul><li>Activa el panel completo como overlay sobre tu página</li><li>Protegido por PIN de 4 dígitos</li><li>Contiene los 7 tabs: Tu Información, Qué Vendes, Cómo Se Ve, Tu Mensaje, Pulso del Negocio, Visual, Configuración</li><li>Funciona desde cualquier dispositivo con navegador web</li><li>No requiere login con email/contraseña — solo el PIN</li></ul><h2 id="cambiar-el-pin" tabindex="-1">Cambiar el PIN <a class="header-anchor" href="#cambiar-el-pin" aria-label="Permalink to &quot;Cambiar el PIN&quot;">​</a></h2><p>Si necesitas cambiar tu PIN:</p><p><strong>Tu panel → Configuración → PIN de Acceso</strong></p><p>Ingresa el PIN actual, el nuevo PIN (4 dígitos) y confirma. Dale clic a <strong>&quot;Guardar PIN&quot;</strong>.</p><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No funciona sin conexión a internet</li><li>No tiene sesión persistente — cada vez que entras necesitas el PIN</li><li>No es una app nativa — funciona en el navegador web</li><li>No tiene opción de &quot;recordar PIN&quot;</li><li>No envía notificaciones push</li></ul><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-maria-actualiza-precios-desde-su-celular" tabindex="-1">Caso: María actualiza precios desde su celular <a class="header-anchor" href="#caso-maria-actualiza-precios-desde-su-celular" aria-label="Permalink to &quot;Caso: María actualiza precios desde su celular&quot;">​</a></h3><p>María tiene una tienda de ropa. Un proveedor le sube los precios y necesita actualizar 5 productos. Desde su celular:</p><ol><li>Abre <code>modamaria.syntiweb.com</code> en Chrome</li><li>Mantiene presionado el logo de su tienda 3 segundos</li><li>Escribe su PIN</li><li>Se abre el panel → va a <strong>Qué Vendes</strong></li><li>Edita los 5 productos con los nuevos precios</li><li>Cierra el panel → los precios ya están actualizados</li></ol><p>Todo sin computadora, sin llamar a nadie, sin esperar.</p>',18)),n(o,null,{default:s(()=>[...a[0]||(a[0]=[c(" Si olvidaste tu PIN, contacta al soporte de SYNTIweb por WhatsApp para restablecerlo. ",-1)])]),_:1}),a[2]||(a[2]=e('<h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/panel-administracion.html">Panel de administración</a> — Los 7 tabs del panel explicados</li><li><a href="/shared/troubleshooting.html">Solución de problemas</a> — Alt+S no abre el panel</li><li><a href="/studio/seccion-config.html">Configuración</a> — Cómo cambiar tu PIN</li></ul>',2))])}const N=i(d,[["render",u]]);export{P as __pageData,N as default};
